import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import response from './response.json';

interface NextToWatch {
  title: string;
  season: number;
  episode: number;
  runtime: string;
}

interface WidgetData {
  nextToWatch: NextToWatch;
  episodesLeft: number;
  estimatedTimeToFinish: string;
}

interface MetaData {
  theme: string;
  dataMode: string;
  layout: string;
  primaryColor: string;
  accentColor: string;
}

export default function Widget() {
  const { nextToWatch, episodesLeft, estimatedTimeToFinish } = response.data as WidgetData;
  const { theme, primaryColor, accentColor } = response.meta as MetaData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 400, bgcolor: theme === 'dark' ? '#303030' : '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: primaryColor }}>
              Next to Watch
            </Typography>
            <Typography variant="body2" sx={{ color: '#B0BEC5' }}>
              {nextToWatch.title}
            </Typography>
            <Stack direction="row" spacing={0.5} sx={{ mt: 0.5 }}>
              <Chip label={`S${nextToWatch.season}`} sx={{ fontSize: '12px', bgcolor: accentColor, color: '#FFFFFF' }} />
              <Chip label={`E${nextToWatch.episode}`} sx={{ fontSize: '12px', bgcolor: accentColor, color: '#FFFFFF' }} />
              <Typography variant="body2" sx={{ color: '#B0BEC5', mt: '2px' }}>
                {nextToWatch.runtime}
              </Typography>
            </Stack>
          </Box>

          <Box>
            <Typography variant="body2" sx={{ color: '#B0BEC5' }}>
              Episodes Left
            </Typography>
            <Typography variant="h4" sx={{ color: primaryColor }}>
              {episodesLeft}
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" sx={{ color: '#B0BEC5' }}>
              Estimated Time to Finish
            </Typography>
            <Typography variant="h6" sx={{ color: primaryColor }}>
              {estimatedTimeToFinish}
            </Typography>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
